import { useEffect, useState } from "react";
import axios from "../api/axios";

export default function MyBookings() {
  const [bookings, setBookings] = useState([]);

  const load = () => {
    axios.get("/bookings/my").then(res => setBookings(res.data));
  };

  useEffect(load, []);

  const cancel = async (id) => {
    await axios.delete(`/bookings/${id}`);
    load();
  };

  return (
    <div style={{ animation: "fadeIn 0.5s ease-out" }}>
      <div style={{ marginBottom: "32px" }}>
        <h2 style={{ fontSize: "2.5rem", color: "var(--text-primary)", marginBottom: "8px", fontWeight: "800", display: "flex", alignItems: "center", gap: "10px" }}>
          <i className="fa-solid fa-ticket-simple" style={{ color: "var(--accent-primary)" }}></i> My Bookings
        </h2>
        <p style={{ color: "var(--text-secondary)", fontSize: "1.05rem", margin: 0 }}>View and manage your parking reservations.</p>
      </div>

      {bookings.length === 0 ? (
        <div style={{ textAlign: "center", padding: "60px 20px", background: "var(--bg-secondary)", borderRadius: "var(--radius-lg)", border: "var(--border-subtle)" }}>
            <i className="fa-regular fa-calendar-xmark fa-3x" style={{ color: "var(--text-muted)", marginBottom: "16px" }}></i>
            <p style={{ color: "var(--text-secondary)", fontSize: "1.1rem" }}>You have no bookings yet.</p>
        </div>
      ) : (
        <>
          {/* ACTIVE BOOKINGS SECTION */}
          <h3 style={{ marginTop: '20px', marginBottom: '20px', color: 'var(--status-success)', display: 'flex', alignItems: 'center', gap: '8px', fontSize: '1.4rem' }}>
             <i className="fa-solid fa-circle-check"></i> Active Reservations
          </h3>
          <div className="grid">
            {bookings.filter(b => b.status === "Active").length === 0 ? <p style={{ color: 'var(--text-muted)' }}>No active reservations.</p> :
              bookings.filter(b => b.status === "Active").map(b => (
                <div className="card" key={b._id} style={{ borderTop: '4px solid var(--status-success)' }}>
                  <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '16px' }}>
                      <h3 style={{ margin: 0, fontSize: '1.2rem', color: 'var(--text-primary)' }}>REF: {b._id.slice(-6).toUpperCase()}</h3>
                      <span style={{ background: 'var(--status-success-bg)', color: 'var(--status-success)', padding: '4px 8px', borderRadius: '6px', fontSize: '0.75rem', fontWeight: '700' }}>ACTIVE</span>
                  </div>
                  <div style={{ flexGrow: 1 }}>
                      <p style={{ margin: '0 0 8px', color: 'var(--text-secondary)' }}><i className="fa-solid fa-location-dot" style={{ width: '20px' }}></i> Slot: <strong>{b.slotId?.slotNumber || "Unknown Slot"}</strong></p>
                      <p style={{ margin: '0 0 8px', color: 'var(--text-secondary)' }}><i className="fa-regular fa-calendar" style={{ width: '20px' }}></i> {new Date(b.startTime).toLocaleDateString()}</p>
                      <p style={{ margin: '0 0 8px', color: 'var(--text-secondary)' }}><i className="fa-regular fa-clock" style={{ width: '20px' }}></i> {new Date(b.startTime).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })} - {new Date(b.endTime).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</p>
                  </div>
                  {/* Actions Link */}
                  <div style={{ display: "flex", gap: "10px", marginTop: "16px", paddingTop: "16px", borderTop: "var(--border-subtle)" }}>
                      <a href={`/receipt/${b._id}`} target="_blank" rel="noreferrer" className="btn-primary" style={{ flex: 1, padding: "10px", fontSize: "0.9rem", textDecoration: "none", background: "var(--status-success)", color: "white" }}>
                          <i className="fa-solid fa-qrcode"></i> View Pass
                      </a>
                      <button
                        onClick={() => cancel(b._id)}
                        style={{ padding: "10px", background: "var(--status-danger-bg)", color: "var(--status-danger)", border: "none", borderRadius: "var(--radius-sm)", cursor: "pointer", fontWeight: "600", transition: "var(--transition)" }}
                        title="Cancel Reservation"
                      >
                        <i className="fa-solid fa-trash-can"></i>
                      </button>
                  </div>
                </div>
              ))
            }
          </div>

          {/* HISTORY SECTION */}
          <h3 style={{ marginTop: '48px', marginBottom: '20px', color: 'var(--text-secondary)', borderTop: '1px solid var(--border-subtle)', paddingTop: '32px', display: 'flex', alignItems: 'center', gap: '8px', fontSize: '1.4rem' }}>
              <i className="fa-solid fa-clock-rotate-left"></i> Booking History
          </h3>
          <div className="grid">
            {bookings.filter(b => b.status !== "Active").length === 0 ? <p style={{ color: 'var(--text-muted)' }}>No past history.</p> :
              bookings.filter(b => b.status !== "Active").map(b => (
                <div className="card" key={b._id} style={{ opacity: 0.8, background: 'var(--bg-primary)', borderTop: b.status === 'Completed' ? '4px solid var(--text-secondary)' : '4px solid var(--status-danger)' }}>
                  <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '16px' }}>
                      <h3 style={{ margin: 0, fontSize: '1.1rem', color: 'var(--text-secondary)' }}>REF: {b._id.slice(-6).toUpperCase()}</h3>
                      <span style={{ fontSize: '0.7rem', background: b.status === 'Completed' ? '#e2e8f0' : 'var(--status-danger-bg)', color: b.status === 'Completed' ? 'var(--text-secondary)' : 'var(--status-danger)', padding: '4px 8px', borderRadius: '4px', fontWeight: 'bold' }}>
                          {b.status.toUpperCase()}
                      </span>
                  </div>
                  <p style={{ margin: '0 0 8px', color: 'var(--text-secondary)', fontSize: '0.9rem' }}><i className="fa-solid fa-location-dot" style={{ width: '20px' }}></i> Slot: <strong>{b.slotId?.slotNumber || "Unknown Slot"}</strong></p>
                  <p style={{ margin: '0 0 8px', color: 'var(--text-secondary)', fontSize: '0.9rem' }}><i className="fa-regular fa-calendar" style={{ width: '20px' }}></i> {new Date(b.startTime).toLocaleDateString()}</p>
                </div>
              ))
            }
          </div>
        </>
      )}
    </div>
  );
}
